    var title = escapeHtml(c.title_at_send || c.contact_type || '');
    var name = escapeHtml(c.name || c.contact_id);
    var dayStr = days === null ? 'no touches' : 'day ' + days;
    var touchStr = touches + ' touch' + (touches === 1 ? '' : 'es');
